async (page) => {
  // Record current URL and comment count before
  const urlBefore = page.url();

  // Find textarea and type
  const textarea = page.getByRole('textbox', { name: 'Add a comment… ⌘↵ to send' });
  await textarea.click();
  await textarea.fill('UAT run 20260303-110924-fbt — comment append test');

  // Wait for Send button to become enabled
  const sendBtn = page.getByRole('button', { name: 'Send' });
  await page.waitForFunction(() => {
    const btn = document.querySelector('button[aria-label="Send"], button:has-text("Send")');
    return btn && !btn.disabled;
  }, { timeout: 3000 }).catch(() => null);

  // Click Send
  await sendBtn.click();

  // Wait for comment to appear
  await page.waitForTimeout(1000);

  // Check URL hasn't changed (no reload)
  const urlAfter = page.url();
  const commentCount = document.querySelectorAll ? null : null;

  return {
    urlBefore,
    urlAfter,
    sameUrl: urlBefore === urlAfter,
    currentUrl: page.url()
  };
}

